import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface EstimatedTaxes {
  quarter: string;
  amountOwed: number;
  incomeBracket: string;
}

interface IncomeDistribution {
  bracket: string;
  percentage: number;
}

interface TaxData {
  estimatedTaxes: EstimatedTaxes;
  incomeDistribution: IncomeDistribution[];
}

export default function Widget() {
  const taxData = response.data as TaxData;
  const { estimatedTaxes, incomeDistribution } = taxData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#333', color: '#FFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Estimated Taxes for {estimatedTaxes.quarter}
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FFC107' }}>
              ${estimatedTaxes.amountOwed.toLocaleString()}
            </Typography>
            <Typography variant="caption" sx={{ color: '#FFF' }}>
              Income Bracket: {estimatedTaxes.incomeBracket}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <PieChart
              series={[
                {
                  data: incomeDistribution.map(d => d.percentage),
                  labels: incomeDistribution.map(d => d.bracket),
                  label: {
                    position: 'outside',
                    connectorStyle: { stroke: '#FFF' },
                  },
                  color: ['#FF5722', '#FFC107', '#FF9800', '#FF7043', '#FFCC80'],
                },
              ]}
            />
          </Box>

          <Stack direction="row" spacing={0.5}>
            {incomeDistribution.map((dist, index) => (
              <Chip
                key={index}
                label={`${dist.bracket}: ${dist.percentage}%`}
                sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#555', color: '#FFF' }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
